  	.hdr.n_type	= 1,
-	.vendor		= GNULINUX_ABI_VENDOR,
-	.flags		= 0
+	.vendor		= GNU_ABI_VENDOR,
+	.flags		= BN_TRANSLATE_OSREL,
+	.trans_osrel	= linux_trans_osrel
  };

  static Elf32_Brandinfo linux_brand = {
  	.brand		= ELFOSABI_LINUX,
  	.machine	= EM_386,
